// ================================================================
// MERGE AI SUMMARY — v2 POLISHED
// Reads from the LangChain OpenAI node and injects summary into slackMessage
// ================================================================

const codeOutput = $('Code: Analyze & Format').first().json;

// ── Extract AI summary from all known output paths ────────────────
let aiSummary = 'Summary unavailable.';
try {
  const openAiJson = $('OpenAI: Generate AI Summary').first().json;
  aiSummary =
    openAiJson?.message?.content?.trim() ||
    openAiJson?.choices?.[0]?.message?.content?.trim() ||
    openAiJson?.content?.[0]?.text?.trim() ||
    openAiJson?.text?.trim() ||
    'Summary unavailable.';
} catch(e) {
  aiSummary = 'AI summary could not be generated.';
}

// ── Inject AI summary into slackMessage ──────────────────────────
const finalSlackMessage = (codeOutput.slackMessage || '').replace('{{AI_SUMMARY}}', aiSummary);

// ── Urgent alert Slack message (polished) ─────────────────────────
const urgentSlackMessage = [
  `🚨 *Action Required — Urgent/Overdue Tasks Detected*`,
  ``,
  `This week\'s Airtable digest has flagged items that need immediate attention:`,
  ``,
  `🔴 *Overdue Tasks:* ${codeOutput.overdueCount}`,
  `⚡ *Urgent / High-Priority Tasks:* ${codeOutput.urgentCount}`,
  ``,
  `Please review the full digest in *#general* and resolve these items before end of day.`,
  ``,
  `_Week: ${codeOutput.weekRange} • ${codeOutput.runTime}_`
].join('\n');

// ── No-activity Slack message ─────────────────────────────────────
const noActivitySlackMessage = [
  `📭 *Weekly Airtable Digest | ${codeOutput.weekRange}*`,
  ``,
  `No records were found in the tracker this week. All quiet! ✅`,
  ``,
  `_🤖 Auto-posted by n8n every Friday • ${codeOutput.runTime}_`
].join('\n');

return [{ json: {
  ...codeOutput,
  aiSummary,
  slackMessage: finalSlackMessage,
  urgentSlackMessage,
  noActivitySlackMessage
}}];

// ================================================================
// WEEKLY DIGEST PROCESSOR — v6 POLISHED
// ================================================================

const records = $input.all();
const now = new Date();

const META_KEYS = new Set(['id', 'createdTime', 'fields', 'tableId', 'baseId']);
const getFields = (record) => {
  const j = record.json || {};
  if (j.fields && typeof j.fields === 'object' && Object.keys(j.fields).length > 0) return j.fields;
  const flat = {};
  for (const [k, v] of Object.entries(j)) { if (!META_KEYS.has(k)) flat[k] = v; }
  return flat;
};

// Week range (Mon–Sun of the current week)
const dow = now.getDay();
const diffToMon = dow === 0 ? -6 : 1 - dow;
const monday = new Date(now);
monday.setDate(now.getDate() + diffToMon);
monday.setHours(0, 0, 0, 0);
const sunday = new Date(monday);
sunday.setDate(monday.getDate() + 6);
const fmt  = d => d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
const fmtShort = d => d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
const weekRange = `${fmt(monday)} – ${fmt(sunday)}`;
const total   = records.length;
const runTime = now.toLocaleString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' });

// ── Empty state ──────────────────────────────────────────────────
if (total === 0) {
  const slackMessage = [
    `📭 *Weekly Airtable Digest | ${weekRange}*`,
    `No records were found this week. All quiet! ✅`,
    ``,
    `_🤖 Auto-posted by n8n every Friday • ${runTime}_`
  ].join('\n');

  return [{ json: {
    hasRecords: false, total: 0, doneCount: 0, completionRate: 0,
    overdueCount: 0, urgentCount: 0, detectedFields: [],
    weekRange, runTime,
    slackColor: '#5f6368',
    slackMessage,
    aiSummaryInput: 'No records were found in Airtable this week. The project tracker is empty for this period.',
    topRecords: []
  }}];
}

// ── Field detection ──────────────────────────────────────────────
const sampleFields = getFields(records[0]);
const fieldNames   = Object.keys(sampleFields);
const find = (candidates) => candidates.find(f => fieldNames.includes(f)) || null;

const nameField     = find(['Name','Title','Subject','Task','Item','Project','Record Name','Label']) || fieldNames[0];
const statusField   = find(['Status','Stage','State','Type','Category','Phase']);
const assigneeField = find(['Assignee','Owner','Assigned To','Responsible','Team Member']);
const dueField      = find(['Due Date','Due','Deadline','Due By','End Date','Target Date']);
const priorityField = find(['Priority','Urgency','Importance','Severity']);

const resolveVal = (raw) => {
  if (raw == null || raw === '') return null;
  if (Array.isArray(raw)) {
    if (!raw.length) return null;
    return raw.map(i => typeof i === 'object' ? (i.name || i.email || i.id || '') : String(i)).filter(Boolean).join(', ');
  }
  if (typeof raw === 'object') return raw.name || raw.email || raw.id || null;
  return String(raw);
};

const isDone = statusField
  ? (r) => { const s = resolveVal(getFields(r)[statusField]) || ''; return /done|complete|closed|finished/i.test(s); }
  : () => false;

const doneCount       = statusField ? records.filter(isDone).length : 0;
const completionRate  = total > 0 ? Math.round((doneCount / total) * 100) : 0;
const barFilled       = Math.round(completionRate / 10);
const bar             = '█'.repeat(barFilled) + '░'.repeat(10 - barFilled);

// ── Aggregations ─────────────────────────────────────────────────
const statusCounts   = {};
const assigneeCounts = {};

if (statusField) records.forEach(r => {
  const k = resolveVal(getFields(r)[statusField]) || 'No Status';
  statusCounts[k] = (statusCounts[k] || 0) + 1;
});

if (assigneeField) records.forEach(r => {
  const raw = getFields(r)[assigneeField];
  const items = Array.isArray(raw) ? raw : [raw];
  items.forEach(n => {
    const k = n == null ? 'Unassigned'
      : typeof n === 'object' ? (n.name || n.email || 'Unknown')
      : String(n || 'Unassigned');
    assigneeCounts[k] = (assigneeCounts[k] || 0) + 1;
  });
});

// ── Overdue detection ─────────────────────────────────────────────
const overdueItems = [];
if (dueField && statusField) {
  records.forEach(r => {
    const f = getFields(r);
    const dueRaw = f[dueField]; if (!dueRaw) return;
    const dueDate = new Date(dueRaw); if (isNaN(dueDate.getTime())) return;
    if (!isDone(r) && dueDate < now) {
      const name     = resolveVal(f[nameField]) || r.json.id || '?';
      const days     = Math.floor((now - dueDate) / 86400000);
      const assignee = assigneeField ? resolveVal(f[assigneeField]) : null;
      overdueItems.push({ name, days, assignee });
    }
  });
}

// ── Urgent detection ──────────────────────────────────────────────
const urgentItems = [];
if (priorityField) records.forEach(r => {
  const f    = getFields(r);
  const pVal = resolveVal(f[priorityField]) || '';
  if (/high|urgent|critical|p0|p1/i.test(pVal)) {
    const name     = resolveVal(f[nameField]) || r.json.id || '?';
    const assignee = assigneeField ? resolveVal(f[assigneeField]) : null;
    urgentItems.push({ name, priority: pVal, assignee });
  }
});

// ── Top records ───────────────────────────────────────────────────
const TOP_N      = 10;
const topRecords = records.slice(0, TOP_N).map((r, i) => {
  const f = getFields(r);
  return {
    name:     resolveVal(f[nameField])     || r.json.id || `Record ${i+1}`,
    status:   statusField   ? resolveVal(f[statusField])   : null,
    assignee: assigneeField ? resolveVal(f[assigneeField]) : null,
    due:      dueField      ? resolveVal(f[dueField])      : null,
    priority: priorityField ? resolveVal(f[priorityField]) : null
  };
});

// ── Build full Slack message (plain mrkdwn, with {{AI_SUMMARY}} placeholder) ──
const recordLines = topRecords.map(rec => {
  const statusPart   = rec.status   ? ` (${rec.status})`   : '';
  const assigneePart = rec.assignee ? ` → ${rec.assignee}` : '';
  let duePart = '';
  if (rec.due) {
    const d = new Date(rec.due);
    if (!isNaN(d.getTime())) duePart = ` — ${fmtShort(d)}`;
    else duePart = ` — ${rec.due}`;
  }
  return `• ${rec.name}${statusPart}${assigneePart}${duePart}`;
}).join('\n');

let statusBreakdownText = '';
if (statusField && Object.keys(statusCounts).length > 0) {
  const rows = Object.entries(statusCounts).sort((a,b) => b[1]-a[1]).map(([k,v]) => `  • ${k}: ${v}`).join('\n');
  statusBreakdownText = `\n\n*Breakdown by Status:*\n${rows}`;
}

let assigneeBreakdownText = '';
if (assigneeField && Object.keys(assigneeCounts).length > 0) {
  const rows = Object.entries(assigneeCounts).sort((a,b) => b[1]-a[1]).slice(0,5).map(([k,v]) => `  • ${k}: ${v}`).join('\n');
  assigneeBreakdownText = `\n\n*Top Contributors:*\n${rows}`;
}

let overdueSection = '';
if (overdueItems.length > 0) {
  const lines = overdueItems.map(i => { const ap = i.assignee ? ` → ${i.assignee}` : ''; return `  • *${i.name}* — ${i.days}d overdue${ap}`; }).join('\n');
  overdueSection = `\n\n*🔴 Overdue Tasks (${overdueItems.length}):*\n${lines}`;
}

let urgentSection = '';
if (urgentItems.length > 0) {
  const lines = urgentItems.map(i => { const ap = i.assignee ? ` → ${i.assignee}` : ''; return `  • *${i.name}* _(${i.priority})_${ap}`; }).join('\n');
  urgentSection = `\n\n*⚡ Urgent / High Priority (${urgentItems.length}):*\n${lines}`;
}

const moreNote = total > TOP_N ? `\n_...and ${total - TOP_N} more — check Airtable for the full list._` : '';

const slackMessage = [
  `📊 *Weekly Airtable Digest | ${weekRange}*`,
  `Total: ${total}   Done: ${doneCount}   Completion: \`${bar}\` ${completionRate}%`,
  `Detected fields: ${fieldNames.join(', ')}`,
  ``,
  `*🤖 AI Summary*`,
  `{{AI_SUMMARY}}`,
  overdueSection ? overdueSection.trim() : null,
  urgentSection  ? urgentSection.trim()  : null,
  ``,
  `*Records (showing ${Math.min(total, TOP_N)} of ${total}):*`,
  recordLines,
  moreNote || null,
  statusBreakdownText  ? statusBreakdownText.trim()  : null,
  assigneeBreakdownText ? assigneeBreakdownText.trim() : null,
  ``,
  `_🤖 Auto-posted by n8n every Friday • ${runTime}_`
].filter(l => l !== null).join('\n');

// ── Colour / status ───────────────────────────────────────────────
let color      = '#36a64f';
let weekStatus = 'Normal Week';
if (overdueItems.length > 0)  { color = '#d93025'; weekStatus = 'Overdue Tasks'; }
else if (urgentItems.length > 0) { color = '#f4b400'; weekStatus = 'High-Priority Tasks'; }

// ── AI summary input ──────────────────────────────────────────────
const statusLines = Object.entries(statusCounts).map(([k,v]) => `${k}: ${v}`).join(', ');
const aiSummaryInput = [
  `Weekly Airtable project tracker digest for ${weekRange}:`,
  `- Total records: ${total}`,
  `- Completed: ${doneCount} (${completionRate}%)`,
  `- Overdue: ${overdueItems.length}${overdueItems.length > 0 ? ' — ' + overdueItems.map(i => i.name).join(', ') : ''}`,
  `- Urgent/high-priority: ${urgentItems.length}${urgentItems.length > 0 ? ' — ' + urgentItems.map(i => i.name).join(', ') : ''}`,
  `- Status breakdown: ${statusLines || 'N/A'}`,
  `- Top assignees: ${Object.entries(assigneeCounts).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([k,v])=>`${k} (${v})`).join(', ') || 'N/A'}`,
  `- Sample tasks: ${topRecords.slice(0,5).map(r => r.name).join(', ')}`
].join('\n');

return [{ json: {
  hasRecords: true,
  total, doneCount, completionRate,
  overdueCount: overdueItems.length,
  urgentCount:  urgentItems.length,
  detectedFields: fieldNames,
  weekRange, runTime,
  slackColor: color,
  weekStatus,
  slackMessage,
  aiSummaryInput,
  topRecords,
  statusCounts,
  assigneeCounts
}}];
